    format      ascii;
    class       volScalarField;
    object      omega;
}

dimensions      [0 0 -1 0 0 0 0];

internalField   uniform 5;

bounds
{
    min 0;
    max 100;
}

boundaryField
{
    inlet
    {
        type            fixedValue;
        value           uniform 5;
    }

    outlet
    {
        type            zeroGradient;
    }

